//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    try{
        lc_sts.setSelectedIndex(0);
        ed_startDt.setValue(scwin.g_sCurrDate.substring(0,6) + "01");
        ed_endDt.setValue(scwin.g_sCurrDate);
        ed_appAcctDeptCd.setValue(scwin.g_sAcctDeptCd);
        if(!$c.gus.cfIsNull(ed_appAcctDeptCd) ){ // 작성부서  조회 
            scwin.f_openPopUp('1',ed_appAcctDeptCd,ed_txt_appAcctDeptNm,'T');
        }
        scwin.getManager(); //관리자 여부 조회
    }catch (e){
        console.log("onUdcCompleted :" + onUdcCompleted);
    }
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
    //TODO 위치변경 후 처리
    $c.gus.cfDisableObjects([ed_txt_appNo, ed_txt_appDeptNm, ed_appDt, ed_txt_regNm, lc_sts, ed_txt_reqTitle, ed_txt_apprvStsNm, ed_txt_rejectRsn]);  //신청정보
    $c.gus.cfDisableObjects([ed_crn, ed_txt_busiNm,ed_txt_repstNm]);  //일반현황
    $c.gus.cfDisableObjects([lc_txnCls, ed_txt_yySellAmt, lc_stmtPrdClsCd, ed_txt_stmtPrdDd, lc_collMoneyCntShtCd, ed_txt_ralyOccpHuse, ed_txt_ralyOccpFcty, ed_txt_ralyOccpEtc]);  //거래조건
    $c.gus.cfDisableObjects([ed_sellAcctDept, ed_txt_sellAcctDeptnm, ed_thisYySellAmt]);  //거래현황
    $c.gus.cfDisableObjects([ed_pldgRalyValue, ed_pldgRalySet, ed_pldgRalySnor, ed_pldgGrtInsr, ed_pldgEtc, ed_saleCreditAmt]); //담보현황
    $c.gus.cfDisableObjects([ed_txt_creditRating, ed_befSellAmt,ed_netIncome,ed_debtRatio,ed_txt_summary]);  
    $c.gus.cfDisableObjects([ed_curLimitAmt, ed_appAmt, ed_addAmt, ed_txt_appRsn]); //요청사항
    $c.gus.cfDisableObjects([btn_crn, btn_sellAcctpDeptnm]);  
    $c.gus.cfDisableObjects([btn_aprv, btn_update, btn_cancel, btn_save, btn_del]);

    //반려사유 그룹 안보이도록 처리
    //chk_Sts.hide();
};

//-------------------------------------------------------------------------
// 담당자 정보를 가져온다.
//-------------------------------------------------------------------------
scwin.getManager = function () {

    try {
        // SELECT 절 
        let param1 = "CD_NM  as COL1 , CD  as COL2 , ''  as COL3 , ''  as COL4 , ''  as COL5 , ''  as COL6 , ''  as COL7 , ''  as COL8 , ''  as COL9 , ''  as COL10";

        // 대상테이블 	
        let param2 = " TB_ZZ002 ";

        // 조건절
        let param3 = "AND GRP_CD = 'FM129' AND USE_YN='1'";
        let param4 =  "CD";
        const strParam = {
                sysCd              : "CommonEBC"           // 시스템코드
                , queryId            : "dinymicQueryTest"    // 쿼리ID
                , param1             : param1                // SELECT
                , param2             : param2                // 대상테이블
                , param3             : param3                // 조건절
                , param4             : param4                // CD
                };
        //데이터셋에 정보설정
        ds_manager_condition.setJSON(strParam);
        $c.sbm.execute(sbm_searchManager);      

    } catch(e){
        console.log("getManager : " +e);
    }
};

//-------------------------------------------------------------------------
// 담당자 정보 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_searchManager_submitdone = function (e) {
    if(e.responseJSON.GAUCE) {
        ds_manager.setJSON(e.responseJSON.GAUCE);
    }

    //ASIS f_getManager();
    let comma = "";
    let j =0;

    for (j=0; j< ds_manager.getRowCount(); j++){
        if(scwin.manager!=""){
            comma=","
        }
        scwin.manager = scwin.manager + comma + ds_manager.getCellData(j, "col1");


        if(ds_manager.getCellData(j,"col2") == scwin.g_sUserId ){ //접속자가 관리자 일때
            scwin.managerYn = "Y";
        }

        tbx_manager.setValue("신청금액이 1천만원초과 신청인 경우 결제상신시 주관부서 담당자("+ scwin.manager +")는 반드시 포함하셔야 합니다.");
    }

    if(scwin.managerYn !="Y"){
        //전삼담당자 확인 추가 2023.10.20 
        scwin.getItManager();
    }
};

//-------------------------------------------------------------------------
// IT담당자 정보를 가져온다.
//-------------------------------------------------------------------------
scwin.getItManager = function () {
    try{
        // SELECT 절 
        let param1 = "FLTR_CD_1  as COL1 , CD  as COL2 , ''  as COL3 , ''  as COL4 , ''  as COL5 , ''  as COL6 , ''  as COL7 , ''  as COL8 , ''  as COL9 , ''  as COL10";

        // 대상테이블 	
        let param2 = " TB_ZZ002";

        // 조건절
        let param3 = "AND GRP_CD = 'ZZ998' AND USE_YN='1' AND FLTR_CD_1 = '"+ scwin.g_sUserId +"'";
        let param4 =  "COL1";
        const strParam = {
                sysCd              : "CommonEBC"           // 시스템코드
                , queryId            : "dinymicQueryTest"    // 쿼리ID
                , param1             : param1                // SELECT
                , param2             : param2                // 대상테이블
                , param3             : param3                // 조건절
                , param4             : param4                // CD
                };
        //데이터셋에 정보설정
        ds_itManager_condition.setJSON(strParam);
        $c.sbm.execute(sbm_searchItManager);
    } catch(e){
        console.log("getItManager : " +e);
    }
};

//-------------------------------------------------------------------------
// IT담당자 정보 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_searchItManager_submitdone = function (e) {
    if(e.responseJSON.GAUCE) {
        ds_itManager.setJSON(e.responseJSON.GAUCE);
    }

    /*if ( !getItManager() ) {
            cfDisableObjects([ed_appAcctDeptCd , ed_txt_appAcctDeptNm, udc_appAcctDeptCd]); //조회조건}*/
    if (ds_itManager.getRowCount() == 0) {
        $c.gus.cfDisableObjects([ed_appAcctDeptCd , ed_txt_appAcctDeptNm, btn_appAcctDeptCd]); //조회조건
    }

};

