//-------------------------------------------------------------------------
// 조회조건 신청부서,사업자번호 조회팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (select_code,txtCode,txtName,sFlag) {
    try {
        let code = txtCode.getValue();
        let name = txtName.getValue();

        switch (select_code) {
            // 관리부서 PopUp 호출
            case '1' :
                //rtnList = cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,null,null,null,null,null); // 거래처
                udc_appAcctDeptCd.setSelectId('retrieveAcctDeptCdInfo');
                udc_appAcctDeptCd.cfCommonPopUp(scwin.udc_appAcctDeptCd_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
                break;
            // 여신대상사업자번호 PopUp 호출
            case '2' :
                //cfCommonPopUp(sCmdName,code,name,sFlag,null,null,null,null,null,null,null,null,null,null,"F",null,null); // 조회조건 사업자번호
                udc_busiNo.setSelectId('retrieveCreditCrnInfo');
                udc_busiNo.cfCommonPopUp(scwin.udc_busiNo_callBackFunc // 콜백 함수
                        , code                            // 화면에서의 ??? Code Element의 Value
                        , name                            // 화면에서의 ??? Name Element의 Value
                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , 'F'                             // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
                break;
            default :
                $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
                break;  
        }          

    } catch (e) {
       console.log("f_openPopUp : " +e);
    }
};

//-------------------------------------------------------------------------
// 관리부서 팝업 콜백(1)
//-------------------------------------------------------------------------
scwin.udc_appAcctDeptCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_appAcctDeptCd.setValue(rtnList[0]);	// 사업자번호
			ed_txt_appAcctDeptNm.setValue(rtnList[1]);	// 사업자명
		} else {
			ed_appAcctDeptCd.setValue(""); //
			ed_txt_appAcctDeptNm.setValue(""); //코드명
		}
    } catch (e) {
       console.log("udc_appAcctDeptCd_callBackFunc " + e);
    }
};

//-------------------------------------------------------------------------
// 여신대상사업자번호 PopUp 콜백(2)
//-------------------------------------------------------------------------
scwin.udc_busiNo_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_busiNo.setValue(rtnList[0]);	// 사업자번호
			ed_txt_crn.setValue(rtnList[1]);	// 사업자명
		} else {
			ed_busiNo.setValue(""); //
			ed_txt_crn.setValue(""); //코드명
		}
    } catch (e) {
       console.log("udc_busiNo_callBackFunc " + e);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    try{
        let ret = await $c.gus.cfValidate([ed_startDt]);
        if (!ret) {
            return false;
        }

        let ret2 = await $c.gus.cfValidate([ed_endDt]);
        if (!ret2) {
            return false;
        }

        if (ret && ret2) {
            ds_crdtMgnt.removeAll();
            $c.sbm.execute(sbm_retrieveCrdtMgnt);
        }
    }catch (e){
        console.log("f_Retrieve : " + e);
    }
};

//-------------------------------------------------------------------------
// 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveCrdtMgnt_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)  return; //onFail
        $c.gus.cfDisableObjects([ed_txt_appNo, ed_txt_appDeptNm, ed_appDt, ed_txt_regNm, lc_sts, ed_txt_reqTitle, ed_txt_apprvStsNm]);  //신청정보
        $c.gus.cfDisableObjects([ed_crn, ed_txt_busiNm,ed_txt_repstNm]);  //일반현황
        $c.gus.cfDisableObjects([lc_txnCls, ed_txt_yySellAmt, lc_stmtPrdClsCd, ed_txt_stmtPrdDd, lc_collMoneyCntShtCd, ed_txt_ralyOccpHuse, ed_txt_ralyOccpFcty, ed_txt_ralyOccpEtc]);  //거래조건
        $c.gus.cfDisableObjects([ed_sellAcctDept, ed_txt_sellAcctDeptnm, ed_thisYySellAmt]);  //거래현황
        $c.gus.cfDisableObjects([ed_pldgRalyValue, ed_pldgRalySet, ed_pldgRalySnor, ed_pldgGrtInsr, ed_pldgEtc]); //담보현황
        $c.gus.cfDisableObjects([ed_txt_creditRating, ed_befSellAmt,ed_netIncome,ed_debtRatio,ed_txt_summary]);  
        $c.gus.cfDisableObjects([ed_curLimitAmt, ed_appAmt, ed_addAmt, ed_txt_appRsn]); //요청사항
        $c.gus.cfDisableObjects([btn_crn, btn_sellAcctpDeptnm]);  

        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        if( ds_crdtMgnt.getRowCount() == 0 ){
            $c.win.alert("조회된 데이터가 없습니다"); 
            $c.gus.cfEnableObjects([btn_add]);
		    $c.gus.cfDisableObjects([btn_update, btn_del, btn_aprv]);
        }

        tbx_totalRows.setValue($c.gus.cfInsertComma(ds_crdtMgnt.getRowCount()));
        if(ds_crdtMgnt.getRowCount() != 0 ){
            ds_crdtMgnt.setRowPosition(0);
            $c.gus.cfGoPrevPosition(gr_crdtMgnt, 0);

            if ( ds_crdtMgnt.getCellData(0, "sts")== "00" ){
                $c.gus.cfEnableObjects([btn_update, btn_del, btn_aprv,btn_add]);
            }else if ( ds_crdtMgnt.getCellData(0,"sts") == "04" && scwin.managerYn == "Y"){
                $c.gus.cfDisableObjects([btn_del, btn_aprv]);
                $c.gus.cfEnableObjects([btn_update,btn_add]);
            }else {
                $c.gus.cfDisableObjects([btn_update, btn_del, btn_aprv]);
            } 
            $c.gus.cfEnableObjects([btn_add]);
		    $c.gus.cfDisableObjects([btn_cancel, btn_save]);


            //if(ds_crdtMgnt.getCellData(ds_crdtMgnt.getRowPosition(),"sts") == "05" ){	//신청상태 반려
            if(ds_crdtMgnt.getCellData(0,"sts") == "05" ){	//신청상태 반려
		        chk_Sts.show();
            }else{
                chk_Sts.hide();
            }
        }

    }catch (e){
        console.log("sbm_retrieveCrdtMgnt_submitdone : " + e);
    }
};

