	ed_endDt.setValue(scwin.g_sCurrDate);
};

//-------------------------------------------------------------------------
// 엑셀저장
//-------------------------------------------------------------------------
scwin.f_GridToExcel = function() {
    if ( ds_crdtMgnt.getRowCount() <= 0){
        $c.win.alert("여신한도 증감신청내역이 존재하지않습니다.");
		return false;
    }
    const options = {
        fileName : "여신한도증감액신청.xlsx" ,//[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "여신한도증감액신청"
    };
    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_crdtMgnt, options, infoArr);

};

